// Comprehensive data source profiling
const dataSources = inputs.data_sources || [];
const profilingResults = {};
const currentTimestamp = new Date().toISOString();

for (const source of dataSources) {
  try {
    console.log(`Profiling data source: ${source.name}`);

    const sourceProfile = {
      source_name: source.name,
      connection_type: source.type,
      profiling_timestamp: currentTimestamp,
      metrics: {},
      quality_scores: {},
      anomalies: [],
      trends: {}
    };

    // Basic data metrics
    const basicQuery = `
      SELECT 
        COUNT(*) as total_records,
        COUNT(DISTINCT ${source.primary_key || 'id'}) as unique_records,
        MIN(${source.timestamp_column || 'created_at'}) as earliest_record,
        MAX(${source.timestamp_column || 'created_at'}) as latest_record,
        COUNT(CASE WHEN ${source.timestamp_column || 'created_at'} >= CURRENT_TIMESTAMP - INTERVAL '24 HOURS' THEN 1 END) as records_last_24h,
        COUNT(CASE WHEN ${source.timestamp_column || 'created_at'} >= CURRENT_TIMESTAMP - INTERVAL '1 HOUR' THEN 1 END) as records_last_1h
      FROM ${source.schema}.${source.table}
    `;

    const basicMetrics = await executeQuery(source.connection, basicQuery);
    sourceProfile.metrics.basic = basicMetrics[0];

    // Data freshness analysis
    sourceProfile.metrics.freshness = {
      hours_since_last_record: calculateHoursSince(basicMetrics[0].latest_record),
      records_per_hour_24h: basicMetrics[0].records_last_24h / 24,
      records_last_hour: basicMetrics[0].records_last_1h,
      is_stale: calculateHoursSince(basicMetrics[0].latest_record) > (source.freshness_threshold_hours || 4)
    };

    // Column-level quality metrics
    const columnMetrics = {};
    for (const column of source.monitored_columns || []) {
      const columnQuery = `
        SELECT 
          COUNT(*) as total_count,
          COUNT(${column.name}) as non_null_count,
          COUNT(DISTINCT ${column.name}) as unique_count,
          ${column.type === 'numeric' ? `AVG(CAST(${column.name} AS FLOAT))` : '0'} as avg_value,
          ${column.type === 'numeric' ? `STDDEV(CAST(${column.name} AS FLOAT))` : '0'} as stddev_value
        FROM ${source.schema}.${source.table}
        WHERE ${source.timestamp_column || 'created_at'} >= CURRENT_TIMESTAMP - INTERVAL '24 HOURS'
      `;

      const columnResult = await executeQuery(source.connection, columnQuery);
      const columnData = columnResult[0];

      columnMetrics[column.name] = {
        completeness_rate: (columnData.non_null_count / columnData.total_count * 100).toFixed(2),
        uniqueness_rate: (columnData.unique_count / columnData.non_null_count * 100).toFixed(2),
        null_count: columnData.total_count - columnData.non_null_count,
        avg_value: columnData.avg_value,
        stddev_value: columnData.stddev_value,
        data_type: column.type
      };

      // Data range validation for numeric columns
      if (column.type === 'numeric' && column.valid_range) {
        const rangeQuery = `
          SELECT COUNT(*) as out_of_range_count
          FROM ${source.schema}.${source.table}
          WHERE ${column.name} IS NOT NULL 
            AND (CAST(${column.name} AS FLOAT) < ${column.valid_range.min} 
                 OR CAST(${column.name} AS FLOAT) > ${column.valid_range.max})
            AND ${source.timestamp_column || 'created_at'} >= CURRENT_TIMESTAMP - INTERVAL '24 HOURS'
        `;

        const rangeResult = await executeQuery(source.connection, rangeQuery);
        columnMetrics[column.name].out_of_range_count = rangeResult[0].out_of_range_count;
        columnMetrics[column.name].range_validity_rate = 
          ((columnData.non_null_count - rangeResult[0].out_of_range_count) / columnData.non_null_count * 100).toFixed(2);
      }

      // Pattern validation for string columns
      if (column.type === 'string' && column.pattern) {
        const patternQuery = `
          SELECT COUNT(*) as pattern_violation_count
          FROM ${source.schema}.${source.table}
          WHERE ${column.name} IS NOT NULL 
            AND ${column.name} NOT REGEXP '${column.pattern}'
            AND ${source.timestamp_column || 'created_at'} >= CURRENT_TIMESTAMP - INTERVAL '24 HOURS'
        `;

        const patternResult = await executeQuery(source.connection, patternQuery);
        columnMetrics[column.name].pattern_violation_count = patternResult[0].pattern_violation_count;
        columnMetrics[column.name].pattern_validity_rate = 
          ((columnData.non_null_count - patternResult[0].pattern_violation_count) / columnData.non_null_count * 100).toFixed(2);
      }
    }

    sourceProfile.metrics.columns = columnMetrics;

    // Data consistency checks
    const consistencyChecks = {};
    for (const check of source.consistency_rules || []) {
      const consistencyQuery = `
        SELECT COUNT(*) as violation_count
        FROM ${source.schema}.${source.table}
        WHERE NOT (${check.condition})
          AND ${source.timestamp_column || 'created_at'} >= CURRENT_TIMESTAMP - INTERVAL '24 HOURS'
      `;

      const consistencyResult = await executeQuery(source.connection, consistencyQuery);
      consistencyChecks[check.name] = {
        violation_count: consistencyResult[0].violation_count,
        check_condition: check.condition,
        severity: check.severity || 'medium'
      };
    }

    sourceProfile.metrics.consistency = consistencyChecks;

    // Calculate quality scores
    sourceProfile.quality_scores = calculateQualityScores(sourceProfile.metrics, source);

    // Detect anomalies
    sourceProfile.anomalies = await detectDataAnomalies(sourceProfile.metrics, source);

    // Trend analysis
    sourceProfile.trends = await analyzeTrends(source, sourceProfile.metrics);

    profilingResults[source.name] = sourceProfile;

  } catch (error) {
    profilingResults[source.name] = {
      source_name: source.name,
      error: error.message,
      profiling_timestamp: currentTimestamp,
      status: 'failed'
    };
  }
}

function calculateHoursSince(timestamp) {
  if (!timestamp) return Infinity;
  const now = new Date();
  const recordTime = new Date(timestamp);
  return Math.round((now - recordTime) / (1000 * 60 * 60));
}

function calculateQualityScores(metrics, source) {
  const scores = {
    freshness_score: 0,
    completeness_score: 0,
    consistency_score: 0,
    validity_score: 0,
    overall_score: 0
  };

  // Freshness score (0-100)
  const hoursSinceLastRecord = metrics.freshness.hours_since_last_record;
  const freshnessThreshold = source.freshness_threshold_hours || 4;
  scores.freshness_score = Math.max(0, 100 - (hoursSinceLastRecord / freshnessThreshold * 100));

  // Completeness score (average of column completeness rates)
  const completenessRates = Object.values(metrics.columns || {})
    .map(col => parseFloat(col.completeness_rate))
    .filter(rate => !isNaN(rate));
  scores.completeness_score = completenessRates.length > 0 
    ? completenessRates.reduce((sum, rate) => sum + rate, 0) / completenessRates.length
    : 100;

  // Consistency score
  const consistencyViolations = Object.values(metrics.consistency || {})
    .reduce((sum, check) => sum + check.violation_count, 0);
  const totalRecords = metrics.basic.records_last_24h || 1;
  scores.consistency_score = Math.max(0, 100 - (consistencyViolations / totalRecords * 100));

  // Validity score (range and pattern validation)
  const validityRates = Object.values(metrics.columns || {})
    .map(col => parseFloat(col.range_validity_rate || col.pattern_validity_rate || 100))
    .filter(rate => !isNaN(rate));
  scores.validity_score = validityRates.length > 0
    ? validityRates.reduce((sum, rate) => sum + rate, 0) / validityRates.length
    : 100;

  // Overall score (weighted average)
  scores.overall_score = Math.round(
    scores.freshness_score * 0.3 +
    scores.completeness_score * 0.25 +
    scores.consistency_score * 0.25 +
    scores.validity_score * 0.2
  );

  return scores;
}

async function detectDataAnomalies(metrics, source) {
  const anomalies = [];

  // Volume anomaly detection
  const currentHourlyRate = metrics.freshness.records_per_hour_24h;
  const expectedRate = source.expected_hourly_rate || 100;
  const volumeDeviation = Math.abs(currentHourlyRate - expectedRate) / expectedRate;

  if (volumeDeviation > 0.5) { // 50% deviation threshold
    anomalies.push({
      type: 'volume_anomaly',
      severity: volumeDeviation > 0.8 ? 'high' : 'medium',
      description: `Data volume anomaly: ${currentHourlyRate.toFixed(1)} records/hour (expected: ${expectedRate})`,
      metric_value: currentHourlyRate,
      expected_value: expectedRate,
      deviation_percentage: (volumeDeviation * 100).toFixed(1)
    });
  }

  // Freshness anomaly
  if (metrics.freshness.is_stale) {
    anomalies.push({
      type: 'freshness_anomaly',
      severity: 'high',
      description: `Data is stale: ${metrics.freshness.hours_since_last_record} hours since last record`,
      metric_value: metrics.freshness.hours_since_last_record,
      threshold: source.freshness_threshold_hours || 4
    });
  }

  // Column-level anomalies
  for (const [columnName, columnMetrics] of Object.entries(metrics.columns || {})) {
    const completenessRate = parseFloat(columnMetrics.completeness_rate);
    if (completenessRate < 90) { // Less than 90% complete
      anomalies.push({
        type: 'completeness_anomaly',
        column: columnName,
        severity: completenessRate < 70 ? 'high' : 'medium',
        description: `Low completeness in ${columnName}: ${completenessRate}%`,
        metric_value: completenessRate,
        threshold: 90
      });
    }

    if (columnMetrics.out_of_range_count > 0) {
      anomalies.push({
        type: 'validity_anomaly',
        column: columnName,
        severity: 'medium',
        description: `${columnMetrics.out_of_range_count} out-of-range values in ${columnName}`,
        metric_value: columnMetrics.out_of_range_count
      });
    }
  }

  return anomalies;
}

async function analyzeTrends(source, currentMetrics) {
  try {
    // Get historical data for trend analysis
    const trendQuery = `
      SELECT 
        DATE(${source.timestamp_column || 'created_at'}) as date,
        COUNT(*) as daily_count
      FROM ${source.schema}.${source.table}
      WHERE ${source.timestamp_column || 'created_at'} >= CURRENT_DATE - INTERVAL 7 DAYS
      GROUP BY DATE(${source.timestamp_column || 'created_at'})
      ORDER BY date
    `;

    const trendData = await executeQuery(source.connection, trendQuery);

    if (trendData.length < 3) return { trend_direction: 'insufficient_data' };

    // Calculate trend direction
    const counts = trendData.map(row => row.daily_count);
    const trendSlope = calculateTrendSlope(counts);

    return {
      trend_direction: trendSlope > 0.1 ? 'increasing' : trendSlope < -0.1 ? 'decreasing' : 'stable',
      trend_slope: trendSlope.toFixed(4),
      daily_counts: trendData,
      avg_daily_count: counts.reduce((sum, count) => sum + count, 0) / counts.length,
      trend_confidence: calculateTrendConfidence(counts)
    };

  } catch (error) {
    return { error: error.message };
  }
}

function calculateTrendSlope(values) {
  const n = values.length;
  const sumX = (n * (n + 1)) / 2;
  const sumXX = (n * (n + 1) * (2 * n + 1)) / 6;
  const sumY = values.reduce((sum, val) => sum + val, 0);
  const sumXY = values.reduce((sum, val, index) => sum + val * (index + 1), 0);

  return (n * sumXY - sumX * sumY) / (n * sumXX - sumX * sumX);
}

function calculateTrendConfidence(values) {
  // Simple confidence calculation based on variance
  const mean = values.reduce((sum, val) => sum + val, 0) / values.length;
  const variance = values.reduce((sum, val) => sum + Math.pow(val - mean, 2), 0) / values.length;
  const coefficientOfVariation = Math.sqrt(variance) / mean;

  // Lower coefficient of variation = higher confidence
  return Math.max(0, Math.min(100, (1 - coefficientOfVariation) * 100));
}

