function calculateOverallHealthStatus(profiling, summary) {
  const totalSources = Object.keys(profiling).length;
  const healthySources = totalSources - (summary.sources_with_anomalies || 0);
  const healthPercentage = (healthySources / totalSources) * 100;

  if (summary.critical_count > 0) return 'critical';
  if (summary.high_count > 0) return 'degraded';
  if (healthPercentage >= 95) return 'healthy';
  if (healthPercentage >= 85) return 'warning';
  return 'unhealthy';
}

function extractKeyMetrics(profiling) {
  const metrics = {
    avg_quality_score: 0,
    total_records_monitored: 0,
    avg_freshness_hours: 0,
    completeness_issues: 0,
    consistency_violations: 0
