    if (sourceData.status === 'failed') continue;

    validSources++;
    metrics.avg_quality_score += sourceData.quality_scores?.overall_score || 0;
    metrics.total_records_monitored += sourceData.metrics?.basic?.records_last_24h || 0;
    metrics.avg_freshness_hours += sourceData.metrics?.freshness?.hours_since_last_record || 0;

    // Count completeness issues
    const columnMetrics = sourceData.metrics?.columns || {};
    for (const [column, columnData] of Object.entries(columnMetrics)) {
      if (parseFloat(columnData.completeness_rate) < 90) {
        metrics.completeness_issues++;
      }
    }

    // Count consistency violations
    const consistencyChecks = sourceData.metrics?.consistency || {};
    metrics.consistency_violations += Object.values(consistencyChecks)
      .reduce((sum, check) => sum + (check.violation_count || 0), 0);
  }

  if (validSources > 0) {
    metrics.avg_quality_score = Math.round(metrics.avg_quality_score / validSources);
    metrics.avg_freshness_hours = Math.round(metrics.avg_freshness_hours / validSources);
  }

  return metrics;
}

