const detailedReports = {};
for (const [sourceName, sourceData] of Object.entries(profilingResults)) {
  if (sourceData.status === 'failed') continue;

  detailedReports[sourceName] = {
    source_name: sourceName,
    quality_score: sourceData.quality_scores?.overall_score || 0,
    health_status: sourceData.quality_scores?.overall_score >= 90 ? 'healthy' : 
                   sourceData.quality_scores?.overall_score >= 70 ? 'warning' : 'unhealthy',
    key_issues: (sourceData.anomalies || []).map(anomaly => ({
      type: anomaly.type,
      severity: anomaly.final_priority || anomaly.severity,
      description: anomaly.description
    })),
    metrics_summary: {
      freshness: sourceData.metrics?.freshness,
      completeness: calculateAvgCompleteness(sourceData.metrics?.columns || {}),
      consistency: Object.keys(sourceData.metrics?.consistency || {}).length
    },
    trend: sourceData.trends?.trend_direction || 'unknown'
  };
}

function calculateAvgCompleteness(columnMetrics) {
  const completenessRates = Object.values(columnMetrics)
    .map(col => parseFloat(col.completeness_rate))
    .filter(rate => !isNaN(rate));

  return completenessRates.length > 0 
    ? Math.round(completenessRates.reduce((sum, rate) => sum + rate, 0) / completenessRates.length)
    : 100;
}

return {
  executive_summary: executiveSummary,
  detailed_reports: detailedReports,
  anomaly_breakdown: {
    by_severity: {
      critical: classifiedAnomalies.critical?.length || 0,
      high: classifiedAnomalies.high?.length || 0,
      medium: classifiedAnomalies.medium?.length || 0,
      low: classifiedAnomalies.low?.length || 0
    },
    by_type: calculateAnomalyTypeBreakdown(classifiedAnomalies)
  },
  recommendations: recommendations
};

function calculateAnomalyTypeBreakdown(anomalies) {
  const breakdown = {};

  Object.values(anomalies).flat().forEach(anomaly => {
    breakdown[anomaly.type] = (breakdown[anomaly.type] || 0) + 1;
  });

  return breakdown;
}

